+export interface RestartOptions {
+  maxAttempts?: number;
+  minDelayMs?: number;
+  maxDelayMs?: number;
+  factor?: number;
+  jitter?: boolean;
+}
+
+export interface SuperviseOptions {
+  restart?: boolean | RestartOptions;
+  queueWhileOffline?: boolean;
+}
+
+export type RestartReason = "close" | "factory";
+
+export interface RestartDetail {
+  delayMs: number;
+  generation: number;
+  reason: RestartReason;
+  restartCount: number;
+}
+
+export class SupervisedWorkerRestartEvent extends Event {
+  readonly detail: RestartDetail;
+
+  constructor(detail: RestartDetail) {
+    super("restart");
+    this.detail = detail;
+  }
+}
+
+export interface SupervisedWorkerEventMap<TMessage> {
+  error: ErrorEvent;
+  message: MessageEvent<TMessage>;
+  messageerror: MessageEvent<unknown>;
+  restart: SupervisedWorkerRestartEvent;
+}
+
+type WorkerFactory = () => Worker;
+type TransferOrOptions = StructuredSerializeOptions | Transferable[];
+
+interface PendingMessage<TMessage> {
+  message: TMessage;
+  transferOrOptions?: TransferOrOptions;
+}
+
+interface ResolvedRestartOptions {
+  enabled: boolean;
+  factor: number;
+  jitter: boolean;
+  maxAttempts: number;
+  maxDelayMs: number;
+  minDelayMs: number;
+}
+
+interface ResolvedOptions {
+  queueWhileOffline: boolean;
+  restart: ResolvedRestartOptions;
+}
+
+const DEFAULT_OPTIONS: ResolvedOptions = {
+  queueWhileOffline: true,
+  restart: {
+    enabled: true,
+    factor: 2,
+    jitter: true,
+    maxAttempts: Number.POSITIVE_INFINITY,
+    maxDelayMs: 5_000,
+    minDelayMs: 100,
+  },
+};
+
+export class SupervisedWorker<TIncoming = unknown, TOutgoing = unknown> extends EventTarget {
+  onerror: ((event: ErrorEvent) => void) | null = null;
+  onmessage: ((event: MessageEvent<TOutgoing>) => void) | null = null;
+  onmessageerror: ((event: MessageEvent<unknown>) => void) | null = null;
+  onrestart: ((event: SupervisedWorkerRestartEvent) => void) | null = null;
+
+  #consecutiveFailures = 0;
+  #factory: WorkerFactory;
+  #generation = 0;
+  #options: ResolvedOptions;
+  #pendingMessages: PendingMessage<TIncoming>[] = [];
+  #restartCount = 0;
+  #restartTimer: ReturnType<typeof setTimeout> | null = null;
+  #stopped = false;
+  #worker: Worker | null = null;
+
+  constructor(factory: WorkerFactory, options: SuperviseOptions = {}) {
+    super();
+    this.#factory = factory;
+    this.#options = resolveOptions(options);
+    this.#spawn();
+  }
+
+  get generation(): number {
+    return this.#generation;
+  }
+
+  get restartCount(): number {
+    return this.#restartCount;
+  }
+
+  get running(): boolean {
+    return this.#worker !== null;
+  }
+
+  override addEventListener<K extends keyof SupervisedWorkerEventMap<TOutgoing>>(
+    type: K,
+    listener: ((event: SupervisedWorkerEventMap<TOutgoing>[K]) => void) | null,
+    options?: boolean | AddEventListenerOptions,
+  ): void;
+  override addEventListener(
+    type: string,
+    listener: EventListenerOrEventListenerObject | null,
+    options?: boolean | AddEventListenerOptions,
+  ): void;
+  override addEventListener(
+    type: string,
+    listener: EventListenerOrEventListenerObject | null,
+    options?: boolean | AddEventListenerOptions,
+  ): void {
+    super.addEventListener(type, listener, options);
+  }
+
+  override removeEventListener<K extends keyof SupervisedWorkerEventMap<TOutgoing>>(
+    type: K,
+    listener: ((event: SupervisedWorkerEventMap<TOutgoing>[K]) => void) | null,
+    options?: boolean | EventListenerOptions,
+  ): void;
+  override removeEventListener(
+    type: string,
+    listener: EventListenerOrEventListenerObject | null,
+    options?: boolean | EventListenerOptions,
+  ): void;
+  override removeEventListener(
+    type: string,
+    listener: EventListenerOrEventListenerObject | null,
+    options?: boolean | EventListenerOptions,
+  ): void {
+    super.removeEventListener(type, listener, options);
+  }
+
+  postMessage(message: TIncoming, transferOrOptions?: TransferOrOptions): void {
+    if (this.#stopped) {
+      throw new Error("Supervised worker has already been terminated.");
+    }
+
+    const worker = this.#worker;
+    if (!worker) {
+      if (!this.#options.queueWhileOffline) {
+        throw new Error("Worker is offline and queueWhileOffline is disabled.");
+      }
+
+      this.#pendingMessages.push({ message, transferOrOptions });
+      return;
+    }
+
+    worker.postMessage(message, transferOrOptions as StructuredSerializeOptions);
+  }
+
+  terminate(): void {
+    if (this.#stopped) {
+      return;
+    }
+
+    this.#stopped = true;
+    this.#pendingMessages = [];
+
+    if (this.#restartTimer) {
+      clearTimeout(this.#restartTimer);
+      this.#restartTimer = null;
+    }
+
+    const worker = this.#worker;
+    this.#worker = null;
+    worker?.terminate();
+  }
+
+  #spawn(pendingRestart: { delayMs: number; reason: RestartReason } | null = null): void {
+    if (this.#stopped) {
+      return;
+    }
+
+    let worker: Worker;
+    try {
+      worker = this.#factory();
+    } catch (error) {
+      this.#emit(createErrorEvent(error));
+      this.#scheduleRestart("factory");
+      return;
+    }
+
+    if (!(worker instanceof Worker)) {
+      this.#emit(createErrorEvent(new TypeError("supervise() factory must return a Worker.")));
+      this.#scheduleRestart("factory");
+      return;
+    }
+
+    this.#worker = worker;
+    this.#generation += 1;
+    this.#consecutiveFailures = 0;
+
+    const generation = this.#generation;
+
+    const handleMessage = (event: Event): void => {
+      if (!this.#isCurrentGeneration(worker, generation)) {
+        return;
+      }
+
+      this.#emit(
+        new MessageEvent<TOutgoing>("message", {
+          data: (event as MessageEvent<TOutgoing>).data,
+        }),
+      );
+    };
+
+    const handleMessageError = (event: Event): void => {
+      if (!this.#isCurrentGeneration(worker, generation)) {
+        return;
+      }
+
+      this.#emit(
+        new MessageEvent("messageerror", {
+          data: (event as MessageEvent<unknown>).data,
+        }),
+      );
+    };
+
+    const handleError = (event: Event): void => {
+      if (!this.#isCurrentGeneration(worker, generation)) {
+        return;
+      }
+
+      const errorEvent = event as ErrorEvent;
+      this.#emit(
+        new ErrorEvent("error", {
+          colno: errorEvent.colno,
+          error: errorEvent.error,
+          filename: errorEvent.filename,
+          lineno: errorEvent.lineno,
+          message: errorEvent.message,
+        }),
+      );
+    };
+
+    const handleClose = (): void => {
+      if (!this.#isCurrentGeneration(worker, generation)) {
+        return;
+      }
+
+      cleanup();
+      this.#worker = null;
+
+      if (!this.#stopped) {
+        this.#scheduleRestart("close");
+      }
+    };
+
+    const cleanup = (): void => {
+      worker.removeEventListener("message", handleMessage);
+      worker.removeEventListener("messageerror", handleMessageError);
+      worker.removeEventListener("error", handleError);
+      worker.removeEventListener("close", handleClose);
+    };
+
+    worker.addEventListener("message", handleMessage);
+    worker.addEventListener("messageerror", handleMessageError);
+    worker.addEventListener("error", handleError);
+    worker.addEventListener("close", handleClose);
+
+    if (pendingRestart) {
+      this.#restartCount += 1;
+      this.#emit(
+        new SupervisedWorkerRestartEvent({
+          delayMs: pendingRestart.delayMs,
+          generation,
+          reason: pendingRestart.reason,
+          restartCount: this.#restartCount,
+        }),
+      );
+    }
+
+    this.#flushPendingMessages(worker, generation);
+  }
+
+  #scheduleRestart(reason: RestartReason): void {
+    if (this.#stopped || this.#restartTimer || !this.#options.restart.enabled) {
+      return;
+    }
+
+    if (this.#consecutiveFailures >= this.#options.restart.maxAttempts) {
+      return;
+    }
+
+    const delayMs = computeRestartDelay(this.#options.restart, this.#consecutiveFailures);
+    this.#consecutiveFailures += 1;
+
+    this.#restartTimer = setTimeout(() => {
+      this.#restartTimer = null;
+      this.#spawn({ delayMs, reason });
+    }, delayMs);
+  }
+
+  #flushPendingMessages(worker: Worker, generation: number): void {
+    while (this.#pendingMessages.length > 0 && this.#isCurrentGeneration(worker, generation)) {
+      const item = this.#pendingMessages.shift();
+      if (!item) {
+        return;
+      }
+
+      try {
+        worker.postMessage(item.message, item.transferOrOptions as StructuredSerializeOptions);
+      } catch (error) {
+        if (!this.#isCurrentGeneration(worker, generation) && this.#options.queueWhileOffline) {
+          this.#pendingMessages.unshift(item);
+          return;
+        }
+
+        this.#emit(createErrorEvent(error));
+      }
+    }
+  }
+
+  #isCurrentGeneration(worker: Worker, generation: number): boolean {
+    return this.#worker === worker && this.#generation === generation;
+  }
+
+  #emit(event: Event): boolean {
+    switch (event.type) {
+      case "error":
+        this.onerror?.(event as ErrorEvent);
+        break;
+      case "message":
+        this.onmessage?.(event as MessageEvent<TOutgoing>);
+        break;
+      case "messageerror":
+        this.onmessageerror?.(event as MessageEvent<unknown>);
+        break;
+      case "restart":
+        this.onrestart?.(event as SupervisedWorkerRestartEvent);
+        break;
+      default:
+        break;
+    }
+
+    return super.dispatchEvent(event);
+  }
+}
+
+export function supervise<TIncoming = unknown, TOutgoing = unknown>(
+  factory: WorkerFactory,
+  options?: SuperviseOptions,
+): SupervisedWorker<TIncoming, TOutgoing> {
+  return new SupervisedWorker<TIncoming, TOutgoing>(factory, options);
+}
+
+function resolveOptions(options: SuperviseOptions): ResolvedOptions {
+  return {
+    queueWhileOffline: options.queueWhileOffline ?? DEFAULT_OPTIONS.queueWhileOffline,
+    restart: resolveRestartOptions(options.restart),
+  };
+}
+
+function resolveRestartOptions(restart: SuperviseOptions["restart"]): ResolvedRestartOptions {
+  if (restart === false) {
+    return {
+      ...DEFAULT_OPTIONS.restart,
+      enabled: false,
+    };
+  }
+
+  if (restart === undefined || restart === true) {
+    return { ...DEFAULT_OPTIONS.restart };
+  }
+
+  return {
+    enabled: true,
+    factor: restart.factor ?? DEFAULT_OPTIONS.restart.factor,
+    jitter: restart.jitter ?? DEFAULT_OPTIONS.restart.jitter,
+    maxAttempts: restart.maxAttempts ?? DEFAULT_OPTIONS.restart.maxAttempts,
+    maxDelayMs: restart.maxDelayMs ?? DEFAULT_OPTIONS.restart.maxDelayMs,
+    minDelayMs: restart.minDelayMs ?? DEFAULT_OPTIONS.restart.minDelayMs,
+  };
+}
+
+function computeRestartDelay(options: ResolvedRestartOptions, attempt: number): number {
+  const rawDelay = Math.min(
+    options.maxDelayMs,
+    options.minDelayMs * Math.max(1, options.factor ** attempt),
+  );
+
+  if (!options.jitter) {
+    return rawDelay;
+  }
+
+  const jitterAmount = rawDelay * 0.2;
+  const minDelay = Math.max(0, rawDelay - jitterAmount);
+  return Math.round(minDelay + Math.random() * jitterAmount * 2);
+}
+
+function createErrorEvent(error: unknown): ErrorEvent {
+  if (error instanceof ErrorEvent) {
+    return new ErrorEvent("error", {
+      colno: error.colno,
+      error: error.error,
+      filename: error.filename,
+      lineno: error.lineno,
+      message: error.message,
+    });
+  }
+
+  if (error instanceof Error) {
+    return new ErrorEvent("error", {
+      error,
+      message: error.message,
+    });
+  }
+
+  return new ErrorEvent("error", {
+    error,
+    message: typeof error === "string" ? error : "Unknown worker error",
+  });
+}

