+import { expect, test } from "bun:test";
+import { supervise, type SupervisedWorkerRestartEvent } from "../src/index.ts";
+
+type WorkerMessage =
+  | { type: "boot" }
+  | { type: "pong"; value: string }
+  | { type: "done"; id: string };
+
+const workerSource = `
+  postMessage({ type: "boot" });
+
+  self.onmessage = (event) => {
+    const data = event.data;
+
+    if (data.type === "ping") {
+      postMessage({ type: "pong", value: data.value });
+      return;
+    }
+
+    if (data.type === "crash") {
+      setTimeout(() => {
+        throw new Error("boom");
+      }, data.delayMs ?? 0);
+      return;
+    }
+
+    if (data.type === "start-long") {
+      setTimeout(() => {
+        postMessage({ type: "done", id: data.id });
+      }, data.messageDelayMs ?? 50);
+
+      setTimeout(() => {
+        throw new Error("boom");
+      }, data.crashAfterMs ?? 0);
+    }
+  };
+`;
+
+test("forwards message events through Worker-like listeners", async () => {
+  const { revoke, worker } = createSupervisedWorker();
+  const seen: string[] = [];
+
+  worker.onmessage = (event) => {
+    seen.push(`property:${String((event.data as WorkerMessage).type)}`);
+  };
+
+  worker.addEventListener("message", (event) => {
+    seen.push(`listener:${String((event as MessageEvent<WorkerMessage>).data.type)}`);
+  });
+
+  try {
+    const boot = await waitForMessage<WorkerMessage>(worker, (data) => data.type === "boot");
+    expect(boot).toEqual({ type: "boot" });
+
+    worker.postMessage({ type: "ping", value: "hello" });
+
+    const pong = await waitForMessage<WorkerMessage>(worker, (data) => data.type === "pong");
+    expect(pong).toEqual({ type: "pong", value: "hello" });
+
+    expect(seen).toContain("property:boot");
+    expect(seen).toContain("listener:boot");
+    expect(seen).toContain("property:pong");
+    expect(seen).toContain("listener:pong");
+  } finally {
+    worker.terminate();
+    revoke();
+  }
+});
+
+test("restarts a crashed worker and keeps forwarding messages", async () => {
+  const { revoke, worker } = createSupervisedWorker();
+
+  try {
+    await waitForMessage<WorkerMessage>(worker, (data) => data.type === "boot");
+
+    const restartPromise = waitForRestart(worker);
+    worker.postMessage({ type: "crash" });
+
+    const restart = await restartPromise;
+    expect(restart.detail.restartCount).toBe(1);
+    expect(restart.detail.reason).toBe("close");
+    expect(worker.restartCount).toBe(1);
+    expect(worker.running).toBe(true);
+
+    worker.postMessage({ type: "ping", value: "after-restart" });
+    const pong = await waitForMessage<WorkerMessage>(
+      worker,
+      (data) => data.type === "pong" && data.value === "after-restart",
+    );
+
+    expect(pong).toEqual({ type: "pong", value: "after-restart" });
+  } finally {
+    worker.terminate();
+    revoke();
+  }
+});
+
+test("queues messages while the worker is offline and flushes them after restart", async () => {
+  const { revoke, worker } = createSupervisedWorker();
+
+  try {
+    await waitForMessage<WorkerMessage>(worker, (data) => data.type === "boot");
+
+    const restartPromise = waitForRestart(worker);
+    worker.postMessage({ type: "crash" });
+
+    await waitFor(() => !worker.running);
+
+    worker.postMessage({ type: "ping", value: "queued-while-offline" });
+
+    await restartPromise;
+
+    const pong = await waitForMessage<WorkerMessage>(
+      worker,
+      (data) => data.type === "pong" && data.value === "queued-while-offline",
+    );
+
+    expect(pong).toEqual({ type: "pong", value: "queued-while-offline" });
+  } finally {
+    worker.terminate();
+    revoke();
+  }
+});
+
+test("does not replay messages that were already sent to a crashed worker", async () => {
+  const { revoke, worker } = createSupervisedWorker();
+  const messages: WorkerMessage[] = [];
+
+  const listener = (event: MessageEvent<WorkerMessage>) => {
+    messages.push(event.data);
+  };
+
+  worker.addEventListener("message", listener);
+
+  try {
+    await waitForMessage<WorkerMessage>(worker, (data) => data.type === "boot");
+
+    const restartPromise = waitForRestart(worker);
+
+    worker.postMessage({
+      crashAfterMs: 10,
+      id: "lost",
+      messageDelayMs: 60,
+      type: "start-long",
+    });
+
+    await restartPromise;
+    await Bun.sleep(120);
+
+    expect(messages.some((message) => message.type === "done" && message.id === "lost")).toBe(
+      false,
+    );
+  } finally {
+    worker.removeEventListener("message", listener);
+    worker.terminate();
+    revoke();
+  }
+});
+
+test("can disable queueing while the worker is offline", async () => {
+  const { revoke, worker } = createSupervisedWorker({
+    queueWhileOffline: false,
+  });
+
+  try {
+    await waitForMessage<WorkerMessage>(worker, (data) => data.type === "boot");
+
+    worker.postMessage({ type: "crash" });
+    await waitFor(() => !worker.running);
+
+    expect(() => worker.postMessage({ type: "ping", value: "nope" })).toThrow(
+      "Worker is offline and queueWhileOffline is disabled.",
+    );
+  } finally {
+    worker.terminate();
+    revoke();
+  }
+});
+
+function createSupervisedWorker(options: Parameters<typeof supervise>[1] = {}) {
+  const url = URL.createObjectURL(new Blob([workerSource], { type: "text/javascript" }));
+  const worker = supervise<
+    | { type: "crash"; delayMs?: number }
+    | { type: "ping"; value: string }
+    | { crashAfterMs?: number; id: string; messageDelayMs?: number; type: "start-long" },
+    WorkerMessage
+  >(() => new Worker(url, { smol: true, type: "module" }), {
+    restart: {
+      factor: 1,
+      jitter: false,
+      maxDelayMs: 20,
+      minDelayMs: 20,
+    },
+    ...options,
+  });
+
+  return {
+    revoke: () => URL.revokeObjectURL(url),
+    worker,
+  };
+}
+
+async function waitForMessage<TMessage>(
+  worker: EventTarget,
+  predicate: (data: TMessage) => boolean,
+  timeoutMs = 1_000,
+): Promise<TMessage> {
+  return waitForEvent(
+    worker,
+    "message",
+    (event) => predicate((event as MessageEvent<TMessage>).data),
+    timeoutMs,
+  ).then((event) => (event as MessageEvent<TMessage>).data);
+}
+
+async function waitForRestart(
+  worker: EventTarget,
+  timeoutMs = 1_000,
+): Promise<SupervisedWorkerRestartEvent> {
+  return waitForEvent(
+    worker,
+    "restart",
+    () => true,
+    timeoutMs,
+  ) as Promise<SupervisedWorkerRestartEvent>;
+}
+
+async function waitForEvent(
+  target: EventTarget,
+  type: string,
+  predicate: (event: Event) => boolean,
+  timeoutMs: number,
+): Promise<Event> {
+  return new Promise((resolve, reject) => {
+    const timeout = setTimeout(() => {
+      target.removeEventListener(type, listener);
+      reject(new Error(`Timed out waiting for ${type}`));
+    }, timeoutMs);
+
+    const listener = (event: Event) => {
+      if (!predicate(event)) {
+        return;
+      }
+
+      clearTimeout(timeout);
+      target.removeEventListener(type, listener);
+      resolve(event);
+    };
+
+    target.addEventListener(type, listener);
+  });
+}
+
+async function waitFor(predicate: () => boolean, timeoutMs = 1_000): Promise<void> {
+  const startedAt = Date.now();
+
+  while (!predicate()) {
+    if (Date.now() - startedAt > timeoutMs) {
+      throw new Error("Timed out waiting for condition");
+    }
+
+    await Bun.sleep(5);
+  }
+}
